// ── NPS NORMALISER (FIXED) ──

const items = $input.all();
if (!items || items.length === 0) return [];

const weekAgo = Date.now() - (7 * 24 * 60 * 60 * 1000);

return items
  .filter(item => {
    const ts = item.json.timestamp;
    if (!ts) return true;
    return new Date(ts).getTime() >= weekAgo;
  })
  .map(item => {
    const text = [
      item.json.feedback_text,
      item.json.feature_requested
    ].filter(Boolean).join(' ');

    return {
      json: {
        id: 'nps_' + (item.json.email || '').replace(/[^a-z0-9]/gi,'') + '_' + Date.now(),
        source: 'nps',
        text: text.trim(),
        score: parseFloat(item.json.nps_score) || null,
        date: item.json.timestamp || new Date().toISOString(),
        user_plan: item.json.plan || 'unknown'
      }
    };
  })
  .filter(i => i.json.text.length > 5); // relaxed filter

// ── SUPPORT NORMALISER (FIXED) ──

const items = $input.all();
if (!items || items.length === 0) return [];

const weekAgo = Date.now() - (7 * 24 * 60 * 60 * 1000);

return items
  .filter(item => {
    const ts = item.json.timestamp;
    if (!ts) return true;
    return new Date(ts).getTime() >= weekAgo;
  })
  .map((item, idx) => {
    // Clean fields (trim keys + values)
    const issueType = (item.json[" issue_type "] || item.json.issue_type || "").trim();
    const desc = (item.json.issue_description || "").trim();
    const priority = (item.json.priority || "").trim().toLowerCase();

    const text = [issueType, desc].filter(Boolean).join('. ').trim();

    // Convert priority → severity number
    let severity = 3;
    if (priority === "high") severity = 1;
    else if (priority === "medium") severity = 3;
    else if (priority === "low") severity = 5;

    return {
      json: {
        id: 'support_' + idx + '_' + Date.now(),
        source: 'support',
        text,
        score: Math.max(1, 10 - (severity * 2)),
        date: item.json.timestamp || new Date().toISOString(),
        user_plan: 'unknown'
      }
    };
  })
  .filter(i => i.json.text.length > 5);

// ── CALL NOTES NORMALISER (FIXED) ──

const items = $input.all();
if (!items || items.length === 0) return [];

const weekAgo = Date.now() - (7 * 24 * 60 * 60 * 1000);

return items
  .filter(item => {
    const d = item.json.date;
    if (!d) return true;
    return new Date(d).getTime() >= weekAgo;
  })
  .map((item, idx) => {
    // Handle dirty keys + trim values
    const pain = (item.json["pain_mentioned "] || item.json.pain_mentioned || "").trim();
    const feature = (item.json["feature_request "] || item.json.feature_request || "").trim();

    const text = [pain, feature].filter(Boolean).join('. ').trim();

    return {
      json: {
        id: 'call_' + idx + '_' + Date.now(),
        source: 'call',
        text,
        score: null, // keep null, handled later
        date: item.json.date || new Date().toISOString(),
        user_plan: 'unknown',
        weight: 4 // 🔥 VERY IMPORTANT (high signal)
      }
    };
  })
  .filter(i => i.json.text.length > 5);

// ── COMMUNITY NORMALISER (FIXED) ──

const items = $input.all();
if (!items || items.length === 0) return [];

const weekAgo = Date.now() - (7 * 24 * 60 * 60 * 1000);

return items
  .filter(item => {
    const d = item.json.date;
    if (!d) return true;
    return new Date(d).getTime() >= weekAgo;
  })
  .map((item, idx) => {
    // Handle dirty keys + trim values
    const message = (item.json["message "] || item.json.message || "").trim();
    const platform = (item.json[" platform "] || item.json.platform || "unknown").trim();

    // Basic sentiment hint (light heuristic)
    let sentiment = "neutral";
    const lower = message.toLowerCase();
    if (lower.includes("bug") || lower.includes("confusing") || lower.includes("issue")) {
      sentiment = "negative";
    } else if (lower.includes("love") || lower.includes("amazing")) {
      sentiment = "positive";
    }

    return {
      json: {
        id: 'community_' + idx + '_' + Date.now(),
        source: 'community',
        text: message,
        score: null,
        sentiment_hint: sentiment,
        date: item.json.date || new Date().toISOString(),
        user_plan: 'unknown',
        platform,
        weight: 2 // medium signal
      }
    };
  })
  .filter(i => i.json.text.length > 5);

// ── DEDUPLICATOR + CAP ──
// Hash-deduplicates by source+text prefix
// Stratified cap: pain signals (score ≤ 4) preserved, rest sampled up to 500

const seen = new Set();
const unique = [];

for (const item of $input.all()) {
  const text = String(item.json.text || '').trim().toLowerCase();
  // Key = source + first 80 chars of text
  const key = (item.json.source || 'unk') + '|' + text.substring(0, 80);
  if (!seen.has(key) && text.length > 10) {
    seen.add(key);
    unique.push(item);
  }
}

// Stratified sampling: keep all pain signals first
const pain   = unique.filter(i => i.json.score !== null && i.json.score <= 4);
const others = unique.filter(i => i.json.score === null || i.json.score > 4);
const capped = [...pain, ...others].slice(0, 500);

// Source breakdown for context
const sourceCounts = {};
capped.forEach(i => {
  sourceCounts[i.json.source] = (sourceCounts[i.json.source] || 0) + 1;
});

// Build week label
const weekStart = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
const fmt = d => d.toLocaleDateString('en-US', { month:'short', day:'numeric' });
const weekLabel = fmt(weekStart) + ' – ' + fmt(new Date()) + ', ' + new Date().getFullYear();

return [{ json: {
  items: capped.map(i => ({
    source:    i.json.source,
    text:      i.json.text,
    score:     i.json.score,
    user_plan: i.json.user_plan
  })),
  meta: {
    total_raw:   $input.all().length,
    after_dedup: unique.length,
    sent_to_ai:  capped.length,
    week:        weekLabel,
    by_source:   sourceCounts
  }
}}];

// ── AI RESPONSE PARSER (ROBUST FIX) ──

const input = $input.first().json;

let raw = '';

// ─────────────────────────────
// STEP 1: Extract raw response
// ─────────────────────────────

// Case 1: OpenRouter standard
if (input.choices && input.choices[0]?.message?.content) {
  raw = input.choices[0].message.content;
}

// Case 2: Your current input (output field)
else if (input.output) {
  raw = input.output;
}

// Case 3: fallback (stringified object)
else if (typeof input === 'string') {
  raw = input;
}

// Case 4: unknown structure
else {
  raw = JSON.stringify(input);
}

raw = String(raw).trim();

let parsed;

// ─────────────────────────────
// STEP 2: Parse JSON safely
// ─────────────────────────────

try {
  parsed = JSON.parse(raw);
} catch (e) {

  // Try markdown block ```json ... ```
  const jsonBlock = raw.match(/```json\s*([\s\S]+?)\s*```/);
  if (jsonBlock) {
    try { parsed = JSON.parse(jsonBlock[1]); } catch(_) {}
  }

  // Try extracting first {...}
  if (!parsed) {
    const objBlock = raw.match(/(\{[\s\S]+\})/);
    if (objBlock) {
      try { parsed = JSON.parse(objBlock[1]); } catch(_) {}
    }
  }

  if (!parsed) {
    throw new Error('[Parse Error] Cannot extract JSON from AI response: ' + raw.slice(0, 300));
  }
}

// ─────────────────────────────
// STEP 3: Validate structure
// ─────────────────────────────

if (!parsed.themes || !Array.isArray(parsed.themes)) {
  throw new Error('[Validation Error] Missing themes array');
}

// ─────────────────────────────
// STEP 4: Get metadata safely
// ─────────────────────────────

let meta;
try {
  meta = $('Deduplicate + Cap').first().json.meta;
} catch(e) {
  meta = { sent_to_ai: 100, week: 'unknown', by_source: {} };
}

const maxFreq = meta.sent_to_ai || 1;

// ─────────────────────────────
// STEP 5: Sanitize themes
// ─────────────────────────────

const themes = parsed.themes.map((t, i) => {

  const freq = Math.max(0, Math.min(parseInt(t.frequency) || 0, maxFreq));
  const sentiment = Math.max(-1, Math.min(parseFloat(t.sentiment_score) || 0, 1));
  const impact = Math.max(0, Math.min(parseFloat(t.impact_score) || 0, 10));

  return {
    theme: String(t.theme || 'Unknown Theme').trim(),
    frequency: freq,
    sentiment_score: sentiment,
    impact_score: impact,
    priority_rank: parseInt(t.priority_rank) || (i + 1),
    suggested_feature: String(t.suggested_feature || '').trim(),
    sample_quotes: Array.isArray(t.sample_quotes)
      ? t.sample_quotes.slice(0, 3).map(q => String(q).trim())
      : [],
    sources: Array.isArray(t.sources)
      ? t.sources.map(s => String(s).trim())
      : []
  };
});

// ─────────────────────────────
// STEP 6: Return clean output
// ─────────────────────────────

return [{
  json: {
    themes,
    summary: String(parsed.summary || '').trim(),
    meta
  }
}];

// ── IMPACT SCORER & RANKER (REFINED) ──

const input = $input.first().json || {};
const themes = Array.isArray(input.themes) ? input.themes : [];
const summary = input.summary || '';
const meta = input.meta || { sent_to_ai: 1 };

const total = meta.sent_to_ai || 1;

// ─────────────────────────────
// STEP 1: Score each theme safely
// ─────────────────────────────

const scored = themes.map((t, idx) => {

  const frequency = Math.max(0, parseInt(t.frequency) || 0);
  const sentiment = Math.max(-1, Math.min(parseFloat(t.sentiment_score) || 0, 1));
  const impact = Math.max(0, Math.min(parseFloat(t.impact_score) || 0, 10));

  const freqRatio  = Math.min(frequency / total, 1);
  const urgency    = (1 - sentiment) / 2;
  const impactNorm = impact / 10;

  const compositeRaw =
    (freqRatio  * 0.40) +
    (impactNorm * 0.35) +
    (urgency    * 0.25);

  // Keep raw + rounded
  const composite = Math.round(compositeRaw * 100);

  // Sentiment display
  let sentLabel = 'Mixed';
  let sentEmoji = '🟡';

  if (sentiment > 0.3) {
    sentLabel = 'Positive';
    sentEmoji = '🟢';
  } else if (sentiment < -0.3) {
    sentLabel = 'Negative';
    sentEmoji = '🔴';
  }

  return {
    ...t,
    frequency,
    sentiment_score: sentiment,
    impact_score: impact,
    composite_score: composite,
    composite_raw: parseFloat(compositeRaw.toFixed(4)), // useful for debugging
    freq_ratio: parseFloat(freqRatio.toFixed(3)),
    urgency: parseFloat(urgency.toFixed(3)),
    sent_label: sentLabel,
    sent_emoji: sentEmoji,
    _original_index: idx // for stable sorting
  };
});

// ─────────────────────────────
// STEP 2: Sort safely (no mutation)
// ─────────────────────────────

const ranked = [...scored]
  .sort((a, b) => {
    // Primary: composite
    if (b.composite_score !== a.composite_score) {
      return b.composite_score - a.composite_score;
    }

    // Secondary: impact
    if (b.impact_score !== a.impact_score) {
      return b.impact_score - a.impact_score;
    }

    // Tertiary: frequency
    if (b.frequency !== a.frequency) {
      return b.frequency - a.frequency;
    }

    // Final: stable fallback
    return a._original_index - b._original_index;
  });

// ─────────────────────────────
// STEP 3: Take top 10
// ─────────────────────────────

const top10 = ranked.slice(0, 10).map((t, i) => ({
  ...t,
  final_rank: i + 1
}));

// ─────────────────────────────
// STEP 4: Clean output
// ─────────────────────────────

return [{
  json: {
    top10,
    summary: String(summary).trim(),
    meta
  }
}];

// ── SLACK MESSAGE FORMATTER (REFINED) ──

const input = $input.first().json || {};

const top10 = Array.isArray(input.top10) ? input.top10 : [];
const summary = String(input.summary || '').trim();
const meta = input.meta || {};

const rankEmoji = ['🥇','🥈','🥉','4️⃣','5️⃣','6️⃣','7️⃣','8️⃣','9️⃣','🔟'];

const sourceMap = {
  nps:       '📋 NPS',
  support:   '🎫 Support',
  reviews:   '🔴 Reddit',
  sales:     '📞 Calls',
  community: '💬 Community'
};

// ─────────────────────────────
// Build theme lines safely
// ─────────────────────────────

const lines = top10.map((t, i) => {

  const sources = Array.isArray(t.sources) ? t.sources : [];
  const src = sources.length
    ? sources.map(s => sourceMap[s] || s).join(', ')
    : 'Unknown';

  const feature = t.suggested_feature || 'No suggestion';

  const quoteRaw = (t.sample_quotes && t.sample_quotes[0]) || '';
  const quote = quoteRaw
    ? `\n   _"${quoteRaw.length > 100 ? quoteRaw.slice(0,100) + '...' : quoteRaw}"_`
    : '';

  const emoji = t.sent_emoji || '🟡';
  const label = t.sent_label || 'Mixed';

  return (
    `${rankEmoji[i] || `${i+1}.`} *${t.theme || 'Unknown Theme'}*\n` +
    `   Score: \`${t.composite_score || 0}/100\` | ${emoji} ${label}\n` +
    `   Freq: ${t.frequency || 0} | ${src}\n` +
    `   ➡ _${feature}_` +
    quote
  );

}).join('\n\n');

// ─────────────────────────────
// Source breakdown
// ─────────────────────────────

const bySource = Object.entries(meta.by_source || {})
  .map(([s, n]) => `${sourceMap[s] || s}: ${n}`)
  .join('  |  ');

// ─────────────────────────────
// Safe meta values
// ─────────────────────────────

const totalRaw = meta.total_raw ?? '-';
const afterDedup = meta.after_dedup ?? '-';
const sentToAI = meta.sent_to_ai ?? '-';
const week = meta.week || 'Current Week';

// ─────────────────────────────
// Final message
// ─────────────────────────────

const message =
  `:bar_chart: *Weekly Feedback Digest — ${week}*\n` +
  `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n` +
  `*${totalRaw}* raw → *${afterDedup}* unique → *${sentToAI}* analysed\n` +
  (bySource ? `${bySource}\n\n` : '\n') +
  `:speech_balloon: *AI Summary*\n${summary || 'No summary available'}\n\n` +
  `:pushpin: *Top ${top10.length} Prioritised Feature Requests*\n` +
  `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n` +
  `${lines || '_No themes detected_'}\n\n` +
  `_Powered by n8n + Llama-3.3-70B · ${new Date().toLocaleDateString()}_`;

// ─────────────────────────────
// Output
// ─────────────────────────────

return [{
  json: {
    message,
    top10,
    meta,
    summary
  }
}];

